          disabled={isLoading || !input.trim()}
          className="absolute right-2 top-2 p-3 bg-teal-600 text-white rounded-full hover:bg-teal-700 disabled:bg-slate-300 transition-colors"
        >
          <Send size={20} />
        </button>
